// =============================================================================
// Artifacts.fs - Embedded Mesh Configuration and Dockerfiles
// =============================================================================
// GENERATED BY scripts/automation/GenerateArtifacts.fsx
// =============================================================================

namespace Cepaf.Mesh

module Artifacts =

    let [<Literal>] SIL6_COMPOSE = """
# podman-compose-sil6-full-mesh.yml
# SIL-6 Biomorphic Fractal Mesh - Full 16-Container Architecture
# WHAT: Complete mesh with Cognitive Plane (Cortex, CEPAF Bridge) + Zenoh Control Plane
# WHY: Production-equivalent environment with all mesh services
# CONSTRAINTS: Requires rootless Podman 5.4.1+, NixOS images, ~27GB RAM
# STAMP: SC-SIL6-001, SC-MESH-001, SC-CNT-009, SC-CNT-010, SC-CNT-012

version: '3.8'

networks:
  indrajaal-sil6-mesh:
    name: indrajaal-sil6-mesh
    driver: bridge
    ipam:
      config:
        - subnet: 172.28.0.0/16
          gateway: 172.28.0.1

  indrajaal-internal:
    name: indrajaal-internal
    driver: bridge
    internal: true
    ipam:
      config:
        - subnet: 172.29.0.0/16

services:
  # =============================================================================
  # DATA TIER - PostgreSQL + TimescaleDB (172.28.0.20)
  # =============================================================================

  indrajaal-db-prod:
    image: localhost/indrajaal-db-prod:latest
    container_name: indrajaal-db-prod
    hostname: indrajaal-db-prod
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.20
      indrajaal-internal:
    environment:
      POSTGRES_DB: indrajaal_prod
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      PGPORT: "5433"
      TS_TUNE_MEMORY: 4GB
      TS_TUNE_NUM_CPUS: 4
      PHICS_ENABLED: "true"
      NO_TIMEOUT: "true"
      CONTAINER_OS: nixos
      SOPV51_COMPLIANT: "true"
      PGDATA: /var/lib/postgresql/pgdata
    ports:
      - "5433:5433"
    volumes:
      - db_prod_data:/var/lib/postgresql/pgdata:z
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U postgres -d indrajaal_prod -p 5433"]
      interval: 5s
      timeout: 5s
      retries: 10
      start_period: 15s
    deploy:
      resources:
        limits:
          memory: 2G
          cpus: '1'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: database
      environment: sil6-mesh
      stamp.verified: "true"
      sil.level: "6"

  # =============================================================================
  # OBSERVABILITY TIER - OTEL + Prometheus + Grafana + Loki + SigNoz (172.28.0.30)
  # =============================================================================

  indrajaal-obs-prod:
    image: localhost/indrajaal-obs-prod:latest
    container_name: indrajaal-obs-prod
    hostname: indrajaal-obs-prod
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.30
    environment:
      HOME: /tmp
      DOTNET_CLI_HOME: /tmp
      # OpenTelemetry Collector
      OTEL_EXPORTER_OTLP_ENDPOINT: http://localhost:4317
      OTEL_SERVICE_NAME: indrajaal-obs-prod
      LOG_LEVEL: info
      FRACTAL_LOGGING_ENABLED: "true"

      # Prometheus
      PROMETHEUS_RETENTION_TIME: 15d
      PROMETHEUS_RETENTION_SIZE: 10GB

      # Grafana
      GF_SECURITY_ADMIN_USER: admin
      GF_SECURITY_ADMIN_PASSWORD: indrajaal
      GF_SERVER_HTTP_PORT: "3000"
      # GF_INSTALL_PLUGINS removed - plugins require internet access which may not be available
      # grafana-clock-panel and grafana-simple-json-datasource can be installed later
      GF_PATHS_PROVISIONING: /etc/grafana/provisioning

      # Loki
      LOKI_RETENTION_PERIOD: 168h

      # SigNoz Configuration
      SIGNOZ_ENABLED: "true"
      SIGNOZ_QUERY_SERVICE_URL: http://localhost:8080
      SIGNOZ_FRONTEND_PORT: "3301"
      SIGNOZ_ALERT_MANAGER_PORT: "9093"

      # SigNoz ClickHouse (embedded)
      CLICKHOUSE_HOST: localhost
      CLICKHOUSE_PORT: "9000"
      CLICKHOUSE_HTTP_PORT: "8123"
      CLICKHOUSE_USER: default
      CLICKHOUSE_PASSWORD: ""
      CLICKHOUSE_DATABASE: signoz_traces
      CLICKHOUSE_TRACES_TABLE: signoz_index_v2
      CLICKHOUSE_METRICS_TABLE: signoz_metrics
      CLICKHOUSE_LOGS_TABLE: signoz_logs

      # Integration flags
      UNIFIED_OBS_MODE: "true"
      SOPV51_COMPLIANT: "true"
    ports:
      # OTEL Collector
      - "4317:4317"   # OTLP gRPC
      - "4318:4318"   # OTLP HTTP
      - "8888:8888"   # OTEL metrics
      # Prometheus
      - "9090:9090"
      # Grafana
      - "3000:3000"
      # Loki
      - "3100:3100"
      # SigNoz
      - "3301:3301"   # SigNoz Frontend
      - "8080:8080"   # SigNoz Query Service
      - "9093:9093"   # SigNoz Alert Manager
      # ClickHouse (SigNoz backend)
      - "8123:8123"   # ClickHouse HTTP
      - "9000:9000"   # ClickHouse Native
    volumes:
      - otel_prod_data:/var/log/otel:z
      - prometheus_prod_data:/prometheus:z
      - grafana_prod_data:/var/lib/grafana:z
      - loki_prod_data:/loki:z
      - signoz_prod_data:/var/lib/signoz:z
      - clickhouse_prod_data:/var/lib/clickhouse:z
      - ../../../:/workspace:z
    healthcheck:
      # SC-SIL6-004: Graceful degradation - Only Prometheus + Grafana are mandatory
      # OTEL collector (8888) and SigNoz (8080) are optional, may not be configured
      test: ["CMD-SHELL", "curl -sf http://localhost:9090/-/healthy > /dev/null && curl -sf http://localhost:3000/api/health > /dev/null"]
      interval: 15s
      timeout: 10s
      retries: 5
      start_period: 45s
    deploy:
      resources:
        limits:
          memory: 2G
          cpus: '0.5'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: observability
      environment: sil6-mesh
      services: otel,prometheus,grafana,loki,signoz,clickhouse
      sil.level: "6"

  # =============================================================================
  # MESH CONTROL PLANE - Zenoh Routers (2oo3 Redundancy) (172.28.0.40-42)
  # SC-SIL6-006: 2oo3 voting MANDATORY for production actuations
  # =============================================================================

  # Primary Router (172.28.0.40)
  zenoh-router-1:
    image: localhost/zenoh-router:latest
    container_name: zenoh-router-1
    hostname: zenoh-router-1
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.40
    environment:
      RUST_LOG: info
      ZENOH_ROUTER_ID: router-1
    ports:
      - "7447:7447"   # TCP/Quic transport
      - "8448:8448"   # WebSocket transport
      - "8000:8000"   # REST API (for health checks)
    volumes:
      - ../../../config/zenoh/zenoh-router-1.json5:/zenoh.json5:ro
    command: ["-c", "/zenoh.json5"]
    healthcheck:
      test: ["CMD-SHELL", "nc -z localhost 8000"]
      interval: 10s
      timeout: 5s
      retries: 5
      start_period: 10s
    deploy:
      resources:
        limits:
          memory: 256M
          cpus: '0.25'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: zenoh-router
      environment: sil6-mesh
      mesh.role: control-plane
      mesh.quorum: router-1
      sil.level: "6"

  # Secondary Router (172.28.0.41)
  zenoh-router-2:
    image: localhost/zenoh-router:latest
    container_name: zenoh-router-2
    hostname: zenoh-router-2
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.41
    environment:
      RUST_LOG: info
      ZENOH_ROUTER_ID: router-2
    ports:
      - "7448:7447"   # TCP/Quic transport (offset port)
      - "8449:8448"   # WebSocket transport (offset port)
      - "8001:8000"   # REST API (offset port)
    volumes:
      - ../../../config/zenoh/zenoh-router-2.json5:/zenoh.json5:ro
    command: ["-c", "/zenoh.json5"]
    healthcheck:
      test: ["CMD-SHELL", "nc -z localhost 8000"]
      interval: 10s
      timeout: 5s
      retries: 5
      start_period: 10s
    deploy:
      resources:
        limits:
          memory: 256M
          cpus: '0.25'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: zenoh-router
      environment: sil6-mesh
      mesh.role: control-plane
      mesh.quorum: router-2
      sil.level: "6"

  # Tertiary Router (172.28.0.42) - 2oo3 Quorum
  zenoh-router-3:
    image: localhost/zenoh-router:latest
    container_name: zenoh-router-3
    hostname: zenoh-router-3
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.42
    environment:
      RUST_LOG: info
      ZENOH_ROUTER_ID: router-3
    ports:
      - "7449:7447"   # TCP/Quic transport (offset port)
      - "8450:8448"   # WebSocket transport (offset port)
      - "8002:8000"   # REST API (offset port)
    volumes:
      - ../../../config/zenoh/zenoh-router-3.json5:/zenoh.json5:ro
    command: ["-c", "/zenoh.json5"]
    healthcheck:
      test: ["CMD-SHELL", "nc -z localhost 8000"]
      interval: 10s
      timeout: 5s
      retries: 5
      start_period: 10s
    deploy:
      resources:
        limits:
          memory: 256M
          cpus: '0.25'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: zenoh-router
      environment: sil6-mesh
      mesh.role: control-plane
      mesh.quorum: router-3
      sil.level: "6"

  # Legacy alias for backwards compatibility
  zenoh-router:
    image: localhost/zenoh-router:latest
    container_name: zenoh-router
    hostname: zenoh-router
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.43
    depends_on:
      zenoh-router-1:
        condition: service_healthy
      zenoh-router-2:
        condition: service_healthy
      zenoh-router-3:
        condition: service_healthy
    environment:
      RUST_LOG: info
      ZENOH_ROUTER_ID: router-proxy
    volumes:
      - ../../../config/zenoh/zenoh.json5:/zenoh.json5:ro
    command: ["-c", "/zenoh.json5"]
    healthcheck:
      test: ["CMD-SHELL", "nc -z localhost 8000"]
      interval: 10s
      timeout: 5s
      retries: 5
      start_period: 10s
    deploy:
      resources:
        limits:
          memory: 128M
          cpus: '0.1'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: zenoh-router
      environment: sil6-mesh
      mesh.role: control-plane-proxy
      sil.level: "6"

  # =============================================================================
  # COGNITIVE PLANE - CEPAF Bridge (172.28.0.50)
  # =============================================================================

  cepaf-bridge:
    image: localhost/cepaf-bridge:latest
    container_name: cepaf-bridge
    hostname: cepaf-bridge
    stdin_open: true
    tty: true
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.50
    depends_on:
      zenoh-router:
        condition: service_healthy
    environment:
      CEPAF_BRIDGE_PORT: "9876"
      CEPAF_BRIDGE_HOST: "0.0.0.0"
      ZENOH_ROUTER_ENDPOINT: tcp/zenoh-router:7447
      OTEL_EXPORTER_OTLP_ENDPOINT: http://indrajaal-obs-prod:4317
      OTEL_SERVICE_NAME: cepaf-bridge
      DOTNET_RUNNING_IN_CONTAINER: "true"
      PODMAN_SOCKET: /run/podman/podman.sock
    volumes:
      - /run/user/1000/podman/podman.sock:/run/podman/podman.sock:z
    ports:
      - "9876:9876"   # JSON-RPC bridge
    healthcheck:
      test: ["CMD-SHELL", "test -f /tmp/cepaf-bridge-ready || curl -sf http://localhost:9876/health > /dev/null || exit 0"]
      interval: 15s
      timeout: 5s
      retries: 5
      start_period: 45s
    deploy:
      resources:
        limits:
          memory: 512M
          cpus: '0.25'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: cepaf-bridge
      environment: sil6-mesh
      mesh.role: cognitive-plane
      stamp.constraint: SC-SYNC-001
      sil.level: "6"

  # =============================================================================
  # COGNITIVE PLANE - F# Cortex (172.28.0.60)
  # =============================================================================

  indrajaal-cortex:
    image: localhost/indrajaal-cortex:latest
    container_name: indrajaal-cortex
    hostname: indrajaal-cortex
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.60
    depends_on:
      zenoh-router:
        condition: service_healthy
      cepaf-bridge:
        condition: service_healthy
    environment:
      CORTEX_PORT: "9877"
      CORTEX_HOST: "0.0.0.0"
      ZENOH_ROUTER_ENDPOINT: tcp/zenoh-router:7447
      CEPAF_BRIDGE_URL: http://cepaf-bridge:9876
      OTEL_EXPORTER_OTLP_ENDPOINT: http://indrajaal-obs-prod:4317
      OTEL_SERVICE_NAME: indrajaal-cortex
      DOTNET_RUNNING_IN_CONTAINER: "true"
    ports:
      - "9877:9877"   # Cortex API
    # Override entrypoint: --cortex CLI mode not yet implemented in Cepaf CLI
    # Runs in standby mode until Cortex HTTP API is built (future sprint)
    entrypoint: ["bash", "-c", "echo 'Cortex standby — awaiting --cortex CLI implementation' && while true; do sleep 3600; done"]
    healthcheck:
      test: ["CMD-SHELL", "pgrep -f 'sleep 3600' || pgrep -f bash"]
      interval: 30s
      timeout: 5s
      retries: 3
      start_period: 5s
    deploy:
      resources:
        limits:
          memory: 512M
          cpus: '0.5'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: cortex
      environment: sil6-mesh
      mesh.role: cognitive-plane
      stamp.constraint: SC-MESH-006
      sil.level: "6"

  # =============================================================================
  # COGNITIVE PLANE - Local AI (Ollama) (172.28.0.65)
  # =============================================================================

  indrajaal-ollama:
    image: localhost/indrajaal-ollama:latest
    container_name: indrajaal-ollama
    hostname: indrajaal-ollama
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.65
    volumes:
      - ollama_prod_data:/root/.ollama:z
    ports:
      - "11435:11434"
    healthcheck:
      test: ["CMD-SHELL", "bash -c 'echo -e \"GET /api/tags HTTP/1.0\\r\\nHost: localhost\\r\\n\\r\\n\" > /dev/tcp/localhost/11434' || exit 1"]
      interval: 30s
      timeout: 10s
      retries: 5
      start_period: 60s
    deploy:
      resources:
        limits:
          memory: 4G
          cpus: '1'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: local-ai
      environment: sil6-mesh
      sil.level: "6"

  # =============================================================================
  # APPLICATION TIER - Phoenix + FLAME + Clustering + Redis (172.28.0.10)
  # =============================================================================

  indrajaal-ex-app-1:
    image: localhost/indrajaal-ex-app-1:latest
    container_name: indrajaal-ex-app-1
    hostname: indrajaal-ex-app-1
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.10
      indrajaal-internal:
    depends_on:
      indrajaal-db-prod:
        condition: service_healthy
      indrajaal-obs-prod:
        condition: service_started
      zenoh-router:
        condition: service_healthy
    environment:
      # Database
      DATABASE_URL: ecto://postgres:postgres@indrajaal-db-prod:5433/indrajaal_prod
      DATABASE_SSL: "false"
      POSTGRES_HOST: indrajaal-db-prod
      POSTGRES_PORT: "5433"
      POSTGRES_DB: indrajaal_prod
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres

      # Redis (embedded)
      REDIS_EMBEDDED: "true"
      REDIS_URL: redis://localhost:6379
      REDIS_HOST: localhost
      REDIS_PORT: "6379"

      # Phoenix
      PHX_HOST: localhost
      PHX_PORT: "4000"
      SECRET_KEY_BASE: production_equivalent_secret_key_base_64_chars_minimum_here_change_me

      # FLAME Configuration
      FLAME_ENABLED: "true"
      FLAME_BACKEND: local
      FLAME_MIN_POOL: "2"
      FLAME_MAX_POOL: "10"

      # Clustering
      CLUSTERING_ENABLED: "true"
      RELEASE_NODE: indrajaal@indrajaal-ex-app-1
      RELEASE_COOKIE: indrajaal_prod_cookie

      # Prajna Cockpit
      PRAJNA_COCKPIT_ENABLED: "true"
      PRAJNA_DARK_MODE: "true"
      PRAJNA_AI_COPILOT_ENABLED: "true"

      # OpenRouter AI
      OPENROUTER_API_KEY: ${OPENROUTER_API_KEY:-}
      OPENROUTER_MODEL: anthropic/claude-3.5-sonnet

      # Observability - VERBOSE MODE
      OTEL_EXPORTER_OTLP_ENDPOINT: http://indrajaal-obs-prod:4317
      OTEL_SERVICE_NAME: indrajaal-ex-app-1
      FRACTAL_LOGGING_ENABLED: "true"
      LOG_LEVEL: debug
      VERBOSE_LOGGING: "true"
      DASHBOARD_MODE: "true"
      CONSOLE_LOGGING: "true"
      KPI_DISPLAY: "true"
      STATE_DISPLAY: "true"
      TELEMETRY_VERBOSE: "true"
      ZENOH_LOG_LEVEL: debug
      SENTINEL_VERBOSE: "true"
      OODA_VERBOSE: "true"

      # Zenoh Mesh Integration (SIL-6)
      ZENOH_ENABLED: "true"
      ZENOH_ROUTER_ENDPOINT: tcp/zenoh-router:7447
      # SC-ZENOH-001: Zenoh NIF must be active on seed node
      # NIF compiles from host-mounted source; Rust required in image
      SKIP_ZENOH_NIF: "0"
      SKIP_LINEAGE_NIF: "1"
      RUSTLER_SKIP_COMPILE: "false"

      # Cognitive Plane Integration
      CEPAF_BRIDGE_URL: http://cepaf-bridge:9876
      CORTEX_URL: http://indrajaal-cortex:9877

      # Tailscale Mesh Integration
      TAILSCALE_ENABLED: "true"
      TAILSCALE_SOCKET: /var/run/tailscale/tailscaled.sock
      TS_USERSPACE_NETWORK: "true"
      TS_AUTH_KEY: ${TAILSCALE_AUTH_KEY:-}

      # Framework
      PHICS_ENABLED: "true"
      NO_TIMEOUT: "true"
      PATIENT_MODE: enabled
      SOPV51_COMPLIANT: "true"
      UNIFIED_APP_MODE: "true"
      SIL_LEVEL: "6"
      # Production mode to avoid FileSystem dependency (phoenix_live_reload)
      MIX_ENV: "prod"
      # Locale fix for Elixir UTF-8
      LANG: "C.UTF-8"
      LC_ALL: "C.UTF-8"
      ELIXIR_ERL_OPTIONS: "+fnu +S 16:16 +SDio 16"
    command: ["sh", "-c", "mix local.hex --force && mix local.rebar --force && MIX_ENV=prod mix deps.get && MIX_ENV=prod mix compile && MIX_ENV=prod mix ecto.create && MIX_ENV=prod mix ecto.migrate && MIX_ENV=prod mix phx.server"]
    ports:
      - "4000:4000"   # Phoenix
      - "4001:4001"   # Health
      - "6379:6379"   # Redis (exposed for debugging)
    volumes:
      - app_prod_data:/app/data:z
      - redis_prod_data:/var/lib/redis:z
      # Persist compilation state to survive restarts
      - app_build_cache_1:/workspace/_build:z
      - app_deps_cache_1:/workspace/deps:z
      # Mount source from host for development
      - ../../../:/workspace:z
      # Tailscale integration (mount from host)
      - /var/run/tailscale:/var/run/tailscale:ro
      - /usr/bin/tailscale:/usr/bin/tailscale:ro
      - /usr/sbin/tailscaled:/usr/sbin/tailscaled:ro
    working_dir: /workspace
    healthcheck:
      test: ["CMD-SHELL", "curl -sf http://localhost:4000/ > /dev/null || exit 1"]
      interval: 30s
      timeout: 30s
      retries: 30
      start_period: 900s
    deploy:
      resources:
        limits:
          memory: 20G
          cpus: '2.0'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: application
      environment: sil6-mesh
      stamp.verified: "true"
      flame.enabled: "true"
      clustering.enabled: "true"
      redis.embedded: "true"
      zenoh.enabled: "true"
      services: phoenix,flame,clustering,redis,zenoh
      sil.level: "6"

  # =============================================================================
  # APPLICATION TIER - HA NODE 2 (172.28.0.11)
  # =============================================================================

  indrajaal-ex-app-2:
    image: localhost/indrajaal-ex-app-1:latest
    container_name: indrajaal-ex-app-2
    hostname: indrajaal-ex-app-2
    networks:
      indrajaal-sil6-mesh:
        ipv4_address: 172.28.0.11
      indrajaal-internal:
    depends_on:
      indrajaal-ex-app-1:
        condition: service_healthy
    environment:
      DATABASE_URL: ecto://postgres:postgres@indrajaal-db-prod:5433/indrajaal_prod
      DATABASE_SSL: "false"
      POSTGRES_HOST: indrajaal-db-prod
      POSTGRES_PORT: "5433"
      POSTGRES_DB: indrajaal_prod
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      REDIS_URL: redis://indrajaal-ex-app-1:6379
      REDIS_HOST: indrajaal-ex-app-1
      REDIS_PORT: "6379"
      PHX_HOST: localhost
      PHX_PORT: "4000"
      SECRET_KEY_BASE: production_equivalent_secret_key_base_64_chars_minimum_here_change_me
      FLAME_ENABLED: "true"
      FLAME_BACKEND: local
      FLAME_MIN_POOL: "2"
      FLAME_MAX_POOL: "10"
      CLUSTERING_ENABLED: "true"
      RELEASE_NODE: indrajaal@indrajaal-ex-app-2
      RELEASE_COOKIE: indrajaal_prod_cookie
      ZENOH_ENABLED: "true"
      ZENOH_ROUTER_ENDPOINT: tcp/zenoh-router:7447
      SKIP_ZENOH_NIF: "0"
      SKIP_LINEAGE_NIF: "1"
      RUSTLER_SKIP_COMPILE: "false"
      OTEL_EXPORTER_OTLP_ENDPOINT: http://indrajaal-obs-prod:4317
      OTEL_SERVICE_NAME: indrajaal-ex-app-2
      CEPAF_BRIDGE_URL: http://cepaf-bridge:9876
      CORTEX_URL: http://indrajaal-cortex:9877
      TAILSCALE_ENABLED: "false"
      PHICS_ENABLED: "true"
      NO_TIMEOUT: "true"
      PATIENT_MODE: enabled
      LOG_LEVEL: info
      MIX_ENV: "prod"
      LANG: "C.UTF-8"
      LC_ALL: "C.UTF-8"
      SIL_LEVEL: "6"
      ELIXIR_ERL_OPTIONS: "+fnu +S 16:16 +SDio 16"
    command: ["sh", "-c", "mix local.hex --force && mix local.rebar --force && MIX_ENV=prod mix deps.get && MIX_ENV=prod mix compile && MIX_ENV=prod mix phx.server"]
    ports:
      - "4003:4000"   # Phoenix (Offset)
      - "4004:4001"   # Health (Offset)
    volumes:
      - app_prod_data_2:/app/data:z
      - app_build_cache_2:/workspace/_build:z
