  app_deps_cache_ml1:
  app_prod_data_2:
  app_prod_data_3:
  app_prod_data_chaya:
  app_prod_data_ml1:
  app_prod_data_ml2:
  app_build_cache_ml2:
  app_deps_cache_ml2:

# =============================================================================
# Architecture: SIL-6 Biomorphic Fractal Mesh (6 Containers)
# =============================================================================
#
# ┌────────────────────────────────────────────────────────────────────────────────┐
# │                     SIL-6 BIOMORPHIC FRACTAL MESH (6 Containers)               │
# ├────────────────────────────────────────────────────────────────────────────────┤
# │                                                                                 │
# │  ┌─────────────────────────────────────────────────────────────────────────┐   │
# │  │ COGNITIVE PLANE (F# .NET 10.0)                                          │   │
# │  │  ┌─────────────────────┐  ┌─────────────────────┐                       │   │
# │  │  │ indrajaal-cortex    │  │ cepaf-bridge        │                       │   │
# │  │  │ :9877               │  │ :9876               │                       │   │
# │  │  │ 172.28.0.60         │  │ 172.28.0.50         │                       │   │
# │  │  └─────────────────────┘  └─────────────────────┘                       │   │
# │  └─────────────────────────────────────────────────────────────────────────┘   │
# │                             │                                                   │
# │                             ▼ Zenoh Pub/Sub                                    │
# │  ┌─────────────────────────────────────────────────────────────────────────┐   │
# │  │ MESH CONTROL PLANE                                                       │   │
# │  │  ┌───────────────────────────────────────────────────────────────┐      │   │
# │  │  │ zenoh-router (eclipse/zenoh:1.0.0)                            │      │   │
# │  │  │ :7447 (TCP) | :8448 (WebSocket) | :8000 (REST API)            │      │   │
# │  │  │ 172.28.0.40                                                    │      │   │
# │  │  └───────────────────────────────────────────────────────────────┘      │   │
# │  └─────────────────────────────────────────────────────────────────────────┘   │
# │                             │                                                   │
# │                             ▼                                                   │
# │  ┌─────────────────────────────────────────────────────────────────────────┐   │
# │  │ APPLICATION PLANE                                                        │   │
# │  │  ┌─────────────────────────────────────────────────────────────────┐    │   │
# │  │  │ indrajaal-ex-app-1 (Phoenix + FLAME + Redis + Zenoh NIF)        │    │   │
# │  │  │ :4000 (HTTP) | :4001 (Health) | :6379 (Redis)                   │    │   │
# │  │  │ 172.28.0.10                                                     │    │   │
# │  │  └─────────────────────────────────────────────────────────────────┘    │   │
# │  └─────────────────────────────────────────────────────────────────────────┘   │
# │                             │                                                   │
# │                             ▼                                                   │
# │  ┌─────────────────────────────────────────────────────────────────────────┐   │
# │  │ DATA + OBSERVABILITY PLANE                                               │   │
# │  │  ┌─────────────────────┐  ┌─────────────────────────────────────────┐   │   │
# │  │  │ indrajaal-db-prod   │  │ indrajaal-obs-prod                      │   │   │
# │  │  │ PostgreSQL+TimescaleDB  │ OTEL + Prometheus + Grafana + Loki     │   │   │
# │  │  │ :5433               │  │ + SigNoz + ClickHouse                   │   │   │
# │  │  │ 172.28.0.20         │  │ 172.28.0.30                             │   │   │
# │  │  └─────────────────────┘  └─────────────────────────────────────────┘   │   │
# │  └─────────────────────────────────────────────────────────────────────────┘   │
# │                                                                                 │
# │  ┌─────────────────────────────────────────────────────────────────────────┐   │
# │  │                    MESH NETWORK (172.28.0.0/16)                          │   │
# │  └─────────────────────────────────────────────────────────────────────────┘   │
# └────────────────────────────────────────────────────────────────────────────────┘
#
# =============================================================================
# Resource Summary
# =============================================================================
#
# | Container           | Memory | CPU | IP Address    | Ports              |
# |---------------------|--------|-----|---------------|--------------------|
# | indrajaal-db-prod   | 4GB    | 4   | 172.28.0.20   | 5433               |
# | indrajaal-obs-prod  | 10GB   | 6   | 172.28.0.30   | 4317,9090,3000,... |
# | zenoh-router        | 512MB  | 1   | 172.28.0.40   | 7447,8448,8000     |
# | cepaf-bridge        | 1GB    | 2   | 172.28.0.50   | 9876               |
# | indrajaal-cortex    | 1GB    | 2   | 172.28.0.60   | 9877               |
# | indrajaal-ex-app-1  | 10GB   | 8   | 172.28.0.10   | 4000,4001,6379     |
# | TOTAL               | ~27GB  | 23  |               |                    |
#
# =============================================================================
# Usage Instructions
# =============================================================================
#
# Build Required Images (if not present):
#   podman build -f Dockerfile.cepaf-bridge -t localhost/cepaf-bridge:latest .
#   podman build -f Dockerfile.cortex -t localhost/indrajaal-cortex:latest .
#
# Start Full Mesh:
#   sa-mesh    # (via devenv shell)
#   # OR
#   podman-compose -f lib/cepaf/artifacts/podman-compose-sil6-full-mesh.yml up -d
#
# Check Status:
#   podman-compose -f lib/cepaf/artifacts/podman-compose-sil6-full-mesh.yml ps
#
# View Logs:
#   podman-compose -f lib/cepaf/artifacts/podman-compose-sil6-full-mesh.yml logs -f
#
# Access Points:
#   Phoenix:       http://localhost:4000
#   Health:        http://localhost:4001/health
#   Prajna:        http://localhost:4000/prajna
#   Copilot:       http://localhost:4000/prajna/copilot
#   Grafana:       http://localhost:3000 (admin/indrajaal)
#   Prometheus:    http://localhost:9090
#   Zenoh REST:    http://localhost:8000/@/router/local
#   CEPAF Bridge:  http://localhost:9876/health
#   Cortex:        http://localhost:9877/health
#
# Shutdown:
#   podman-compose -f lib/cepaf/artifacts/podman-compose-sil6-full-mesh.yml down
#
# Cleanup (with volumes):
#   podman-compose -f lib/cepaf/artifacts/podman-compose-sil6-full-mesh.yml down -v
# =============================================================================
"""

    let [<Literal>] SWARM_14_COMPOSE = """
# podman-compose-swarm-14.yml
# Phase 4+7: Full 15-Container Swarm Architecture with Boot Optimization
# =============================================================================
# WHAT: Complete 15-container mesh with HA, Cognitive Plane, and Satellites
# WHY: Production-equivalent environment with full high-availability
# CONSTRAINTS: Requires rootless Podman 5.4.1+, ~40GB RAM
#
# MATHEMATICAL FOUNDATIONS (Phase 3.5):
#   - DAG: 15 nodes, 7 tiers, topological ordering
#   - CPM: Critical path ~120s (db → zenoh → bridge → app-1 → app-2)
#   - RCPSP: Memory 40GB, CPU 32 cores bounded
#   - DFA: 14 states per container lifecycle
#
# PHASE 7 OPTIMIZATIONS (2026-01-18):
#   - SC-OPT-005: Pre-compiled BEAM in image
#   - SC-OPT-006: Wave parallelization (W2+W3)
#   - SC-OPT-007: BEAM volume caching for faster restarts
#   - SC-OPT-008: Boot metrics published to Zenoh
#   - PHICS: Physical Interface Control System (<50ms latency)
#
# STAMP Constraints:
#   SC-SWARM-001 to SC-SWARM-020: Full swarm orchestration
#   SC-SIL6-006: 2oo3 voting for Zenoh quorum
#   SC-SIL6-001 to SC-SIL6-015: SIL-6 Biomorphic Extended Safety
#   SC-PHICS-001 to SC-PHICS-010: Physical Interface Control
#
# Wave Architecture (with parallelization):
#   Wave 1 (Foundation):      indrajaal-db-prod (sequential)
#   Wave 2 (Obs + Zenoh):     indrajaal-obs-prod, zenoh-router-{1,2,3} (PARALLEL)
#   Wave 3 (Cognitive):       cepaf-bridge, indrajaal-cortex (early start after quorum)
#   Wave 4 (Application):     indrajaal-ex-app-1
#   Wave 5 (HA + Satellites): indrajaal-ex-app-{2,3}, indrajaal-chaya, ml-runner-{1,2} (PARALLEL)
# =============================================================================

version: '3.8'

networks:
  indrajaal-swarm-mesh:
    driver: bridge
    ipam:
      config:
        - subnet: 172.30.0.0/16
          gateway: 172.30.0.1

  indrajaal-internal:
    driver: bridge
    internal: true
    ipam:
      config:
        - subnet: 172.31.0.0/16

# =============================================================================
# WAVE 1: FOUNDATION (DB) - IP: 172.30.0.20
# =============================================================================
services:
  indrajaal-db-prod:
    image: localhost/indrajaal-db-prod:latest
    container_name: indrajaal-db-prod
    hostname: indrajaal-db-prod
    networks:
      indrajaal-swarm-mesh:
        ipv4_address: 172.30.0.20
      indrajaal-internal:
    environment:
      POSTGRES_DB: indrajaal_prod
      POSTGRES_USER: postgres
      POSTGRES_PASSWORD: postgres
      PGPORT: "5433"
      TS_TUNE_MEMORY: 4GB
      TS_TUNE_NUM_CPUS: 4
      PHICS_ENABLED: "true"
      NO_TIMEOUT: "true"
      CONTAINER_OS: nixos
      SOPV51_COMPLIANT: "true"
      PGDATA: /var/lib/postgresql/pgdata
    ports:
      - "5433:5433"
    volumes:
      - db_swarm_data:/var/lib/postgresql/pgdata:z
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U postgres -d indrajaal_prod -p 5433"]
      interval: 5s
      timeout: 5s
      retries: 10
      start_period: 15s
    deploy:
      resources:
        limits:
          memory: 4G
          cpus: '4'
    restart: unless-stopped
    labels:
      project: indrajaal
      component: database
      environment: swarm-14
      wave: "1"
      priority: "P0"
      sil.level: "6"

# =============================================================================
# WAVE 2: OBSERVABILITY (172.30.0.30) + ZENOH 2oo3 QUORUM (172.30.0.40-42)
# =============================================================================

  indrajaal-obs-prod:
    image: localhost/indrajaal-obs-unified:nixos-devenv
    container_name: indrajaal-obs-prod
    hostname: indrajaal-obs-prod
    networks:
      indrajaal-swarm-mesh:
        ipv4_address: 172.30.0.30
    environment:
      OTEL_EXPORTER_OTLP_ENDPOINT: http://localhost:4317
      OTEL_SERVICE_NAME: indrajaal-obs-prod
      LOG_LEVEL: info
      FRACTAL_LOGGING_ENABLED: "true"
      PROMETHEUS_RETENTION_TIME: 15d
      GF_SECURITY_ADMIN_USER: admin
      GF_SECURITY_ADMIN_PASSWORD: indrajaal
      GF_SERVER_HTTP_PORT: "3000"
      UNIFIED_OBS_MODE: "true"
    ports:
      - "4317:4317"
      - "4318:4318"
      - "9090:9090"
      - "3000:3000"
      - "3100:3100"
    volumes:
      - otel_swarm_data:/var/log/otel:z
      - prometheus_swarm_data:/prometheus:z
      - grafana_swarm_data:/var/lib/grafana:z
      - loki_swarm_data:/loki:z
      - ../../../:/workspace:z
    healthcheck:
      test: ["CMD-SHELL", "curl -sf http://localhost:9090/-/healthy && curl -sf http://localhost:3000/api/health"]
      interval: 15s
      timeout: 10s
      retries: 5
      start_period: 45s
    deploy:
      resources:
        limits:
          memory: 10G
          cpus: '6'
    restart: unless-stopped
    labels:
