    let [<Literal>] DOCKERFILE_DB = """
# Dockerfile.db - SIL-2 compliant TimescaleDB image
# Track: infra-f#-cepa
# Purpose: Standalone verification image for the data layer.

FROM docker.io/timescale/timescaledb:latest-pg17

# Agent: Add SOPv5.11 compliance markers
RUN mkdir -p /nix/store /nix/var /workspace && \
    touch /.phics-container && \
    echo "timescaledb-nixos" > /.container-type

# Agent: Set environment for CEPAF# orientation
ENV SOPV5_COMPLIANT=true
ENV CONTAINER_OS=nixos
ENV PHICS_ENABLED=true

# Agent: Default working directory
WORKDIR /workspace

# Default command inherited from base
"""

    let [<Literal>] DOCKERFILE_BASE = """
# SOPv5.1 Base Container
# Framework: SOPv5.1 + PHICS + TPS + STAMP
# Purpose: Universal Base Image with NixOS tools + Tailscale Mesh Capability

# Stage 1: Extract Static Tailscale Binaries
FROM docker.io/tailscale/tailscale:stable as tailscale-source

# Stage 2: Build NixOS Base
FROM ghcr.io/nixos/nix:latest

# Agent: Install core dependencies
RUN nix-channel --add https://nixos.org/channels/nixos-unstable nixpkgs && \
    nix-channel --update

# Agent: Install Elixir environment & Tools
RUN nix-env -iA nixpkgs.elixir_1_19 \
                nixpkgs.erlang_28 \
                nixpkgs.rebar3 \
                nixpkgs.gitMinimal \
                nixpkgs.bash \
                nixpkgs.coreutils \
                nixpkgs.gnumake \
                nixpkgs.gcc \
                nixpkgs.postgresql_17 \
                nixpkgs.redis \
                nixpkgs.podman \
                nixpkgs.cacert \
                nixpkgs.iptables \
                nixpkgs.iproute2 nixpkgs.hostname nixpkgs.curl nixpkgs.which nixpkgs.jq

# Agent: Inject Tailscale Binaries (Universal Mesh Capability)
# We copy from the official image to ensure we get the static Go binaries
COPY --from=tailscale-source /usr/local/bin/tailscaled /usr/local/bin/tailscaled
COPY --from=tailscale-source /usr/local/bin/tailscale /usr/local/bin/tailscale
RUN mkdir -p /var/run/tailscale /var/cache/tailscale /var/lib/tailscale

# Agent: Create PHICS markers
RUN touch /.phics-container && \
    mkdir -p /workspace && \
    echo "sopv51-base" > /.container-type

# Agent: Set environment
ENV CONTAINER_ENFORCEMENT=false
ENV PHICS_ENABLED=true
ENV NO_TIMEOUT=true
ENV ELIXIR_ERL_OPTIONS="+S 16"
ENV SOP_V51_MODE=enabled
ENV TPS_METHODOLOGY=active
ENV STAMP_INTEGRATION=enabled

# Agent: Set working directory
WORKDIR /workspace

# Agent: Default command
CMD ["sleep", "infinity"]
"""

    let [<Literal>] DOCKERFILE_OBS = """
# SOPv5.1 Observability Monolith (Dev/Test)
# Combines Prometheus, Grafana, ClickHouse, OTEL into one container for simplified dev/demo usage.

FROM localhost/sopv51-base:latest

# Install Observability Stack and utilities
RUN nix-channel --update && \
    nix-env -iA nixpkgs.prometheus \
                nixpkgs.grafana \
                nixpkgs.clickhouse \
                nixpkgs.opentelemetry-collector \
                nixpkgs.curl \
                nixpkgs.netcat \
                nixpkgs.dotnet-sdk_10

# Setup Directories
RUN mkdir -p /var/lib/grafana \
             /var/lib/clickhouse \
             /var/lib/prometheus \
             /app/config/prometheus \
             /app/config/grafana \
             /app/config/otel-collector \
             /var/log/clickhouse-server \
             /var/log/grafana && \
    chmod -R 777 /var/log /var/lib/grafana /var/lib/clickhouse /var/lib/prometheus /app/config

# Copy Configs
COPY monitoring/prometheus.yml /app/config/prometheus/prometheus.yml
COPY monitoring/grafana/grafana.ini /app/config/grafana/grafana.ini
COPY containers/signoz/config/clickhouse/clickhouse-config.xml /app/config/clickhouse/clickhouse-config.xml
COPY containers/signoz/config/clickhouse/clickhouse-users.xml /app/config/clickhouse/clickhouse-users.xml
COPY containers/signoz/config/otel-collector/otel-collector-standalone.yaml /app/config/otel-collector/config.yaml

# Build and Publish F# ObsSupervisor (Genetic Self-Containment)
COPY lib/cepaf/src/Cepaf.ObsSupervisor /app/src/Cepaf.ObsSupervisor
WORKDIR /app/src/Cepaf.ObsSupervisor
RUN dotnet publish -c Release --self-contained -r linux-x64 -o /app/bin

# Fix Shebangs & Symlinks
RUN ln -sf $(which bash) /bin/bash && \
    ln -sf $(which sh) /bin/sh && \
    ln -sf $(which curl) /bin/curl

WORKDIR /app
# Use Published F# ObsSupervisor as the entrypoint (self-contained, no runtime dependency)
CMD ["sh", "-c", "export HOME=/tmp && export DOTNET_CLI_HOME=/tmp && /app/bin/Cepaf.ObsSupervisor"]
"""

    let [<Literal>] DOCKERFILE_APP = """
# SOPv5.1 Elixir Application (SIL-6 Biomorphic)
FROM localhost/sopv51-base:latest

LABEL sopv51.version="5.1.0"
LABEL sopv51.phics.enabled="true"

WORKDIR /workspace

# Genetic Re-Synthesis Environment
# XLA_BUILD=false downloads prebuilt binaries (bazel not available in container)
# SKIP_ZENOH_NIF=1 — Zenoh accessed via mesh network, not in-process NIF
ENV XLA_TARGET=cpu
ENV XLA_BUILD=false
ENV SKIP_ZENOH_NIF=1
ENV SKIP_LINEAGE_NIF=1
ENV MIX_ENV=prod
ENV SECRET_KEY_BASE=container-build-placeholder-key-will-be-overridden-at-runtime-0123456789abcdef

# TARGETED GENETIC INJECTION: Only essential source DNA
COPY mix.exs mix.lock ./
COPY config ./config
COPY lib ./lib
COPY priv ./priv
COPY scripts/containers/entrypoint.sh /usr/local/bin/entrypoint.sh

# Install toolchain inside container (musl-libc alignment)
# gnumake + gcc needed for NIF compilation (bcrypt, jason_native, etc.)
RUN nix-channel --update && \
    nix-env -iA nixpkgs.elixir_1_19 \
                nixpkgs.erlang_28 \
                nixpkgs.tini \
                nixpkgs.gnumake \
                nixpkgs.gcc \
                nixpkgs.cmake

RUN chmod +x /usr/local/bin/entrypoint.sh

# Force NIF compilation inside the container toolchain
RUN mix local.hex --force && \
    mix local.rebar --force && \
    mix deps.get && \
    mix compile

ENTRYPOINT ["tini", "--", "/usr/local/bin/entrypoint.sh"]
CMD ["phx.server"]
"""

    let [<Literal>] DOCKERFILE_BRIDGE = """
# Dockerfile.cepaf-bridge - F# CEPAF Bridge Service
# Version: 1.0.0
# Context: SIL-6 Biomorphic Fractal Mesh - Cognitive Plane
# STAMP: SC-SIL6-001, SC-SYNC-001, SC-MESH-001

# Build stage - compile F# project
FROM mcr.microsoft.com/dotnet/sdk:10.0 AS build
WORKDIR /src

# Copy the entire lib structure to preserve relative paths for project references
COPY lib/ /src/lib/

# Restore and publish the CEPAF Bridge
WORKDIR /src/lib/cepaf/src/Cepaf.Bridge
RUN dotnet restore Cepaf.Bridge.fsproj
RUN dotnet publish Cepaf.Bridge.fsproj -c Release -o /app/publish

# Runtime stage - minimal image
FROM mcr.microsoft.com/dotnet/runtime:10.0
WORKDIR /app

# Install curl for health checks
RUN apt-get update && apt-get install -y --no-install-recommends curl && rm -rf /var/lib/apt/lists/*

# Copy published application
COPY --from=build /app/publish .

# Expose JSON-RPC port for Elixir-F# bridge communication
EXPOSE 9876

# Health check
HEALTHCHECK --interval=15s --timeout=5s --start-period=30s --retries=3 \
    CMD curl -f http://localhost:9876/health || exit 1

# Environment variables
ENV CEPAF_BRIDGE_PORT=9876
ENV CEPAF_BRIDGE_HOST=0.0.0.0
ENV DOTNET_RUNNING_IN_CONTAINER=true

# SIL-6 Labels
LABEL project="indrajaal" \
      component="cepaf-bridge" \
      version="1.0.0" \
      sil.level="6" \
      stamp.constraint="SC-SYNC-001" \
      mesh.role="cognitive-plane"

ENTRYPOINT ["dotnet", "cepaf-bridge.dll"]
"""

